import {TriStateCheckbox as TriStateCheckboxPrime, type TriStateCheckboxProps} from "primereact/tristatecheckbox";
import {useSelectionController} from "../../../hooks";

export const TriStateCheckbox = (props:TriStateCheckboxProps)=>{
    const { value, onChange } = useSelectionController({
        mode: 'tristate',
        defaultValue: false // Start at false
    });

    return <TriStateCheckboxPrime value={value} onChange={()=>onChange()} {...props} />
}
